1	export type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	export type Step = { op: "quote"; items: Item[] };
3	export type Result = { premium: number };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	};
12	
13	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
14	
15	const quotePremium = (items: Item[]): number => {
16	  const base = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
17	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
18	  return base + firstInsuranceSurcharge + PROCESSING_FEE;
19	};
20	
21	export const runScenario = (input: {
22	  customer: { yearsWithMHPCO: number };
23	  steps: Step[];
24	}): { results: Result[] } => {
25	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
26	  return { results };
27	};
